import boto3
from botocore.exceptions import ClientError
import sys

def list_s3_files(bucket_name, access_key=None, secret_key=None):
    try:
        if access_key and secret_key:
            s3_client = boto3.client(
                's3',
                aws_access_key_id=access_key,
                aws_secret_access_key=secret_key
            )
        else:
            s3_client = boto3.client('s3')
        
        response = s3_client.list_objects_v2(Bucket=bucket_name)
        
        if 'Contents' in response:
            print(f"Files in bucket '{bucket_name}':")
            for obj in response['Contents']:
                print(f"  - {obj['Key']} ({obj['Size']} bytes)")
        else:
            print(f"No files found in bucket '{bucket_name}'")
            
    except ClientError as e:
        print(f"Error: {e}")
        sys.exit(1)

if __name__ == "__main__":
    bucket = 'demo-bucket'
    
    # Option 1: Pass credentials as command line arguments
    if len(sys.argv) == 3:
        list_s3_files(bucket, sys.argv[1], sys.argv[2])
    else:
        # Option 2: Use default credential chain (recommended)
        print("Using default AWS credentials")
        list_s3_files(bucket)